// ============================================================
// HydraNet - DMA Managers API Route
// Dedicated endpoint for DMAManager table operations
// ============================================================

import { NextRequest, NextResponse } from 'next/server'
import prisma from '@/lib/prisma'
import { hashPassword, checkEmailUniqueness } from '@/lib/auth'

// GET /api/dma-managers - List all DMA managers
export async function GET(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const utilityId = searchParams.get('utilityId')

    const managers = await prisma.dMAManager.findMany({
      where: utilityId ? { utilityId } : undefined,
      include: {
        utility: { select: { id: true, name: true } },
        dma: { select: { id: true, name: true } },
      },
      orderBy: { name: 'asc' },
    })

    // Transform to include utilityId/dmaId/dmaName at top level for compatibility
    const transformedManagers = managers.map((manager) => ({
      id: manager.id,
      name: manager.name,
      email: manager.email,
      phone: manager.phone,
      status: manager.status,
      role: 'dma_manager',
      utilityId: manager.utilityId,
      utilityName: manager.utility.name,
      dmaId: manager.dmaId,
      dmaName: manager.dma?.name || null,
      createdAt: manager.createdAt,
    }))

    return NextResponse.json(transformedManagers)
  } catch (error) {
    console.error('Error fetching DMA managers:', error)
    return NextResponse.json({ error: 'Failed to fetch DMA managers' }, { status: 500 })
  }
}

// POST /api/dma-managers - Create a new DMA manager
export async function POST(request: NextRequest) {
  try {
    const data = await request.json()

    // Validate required fields
    if (!data.name || !data.email || !data.utilityId) {
      return NextResponse.json(
        { error: 'Name, email, and utilityId are required' },
        { status: 400 }
      )
    }

    // Check email uniqueness across all user tables
    const emailCheck = await checkEmailUniqueness(data.email)
    if (!emailCheck.isUnique) {
      return NextResponse.json(
        { error: `This email is already in use by a ${emailCheck.foundIn}` },
        { status: 400 }
      )
    }

    // Hash the password
    const hashedPassword = await hashPassword(data.password || 'dma123')

    // If assigning to a DMA, unassign any existing manager from this DMA first
    if (data.dmaId) {
      await prisma.$executeRaw`
        UPDATE "DMAManager" 
        SET "dmaId" = NULL, "updatedAt" = NOW()
        WHERE "dmaId" = ${data.dmaId}
      `
    }

    // Create the DMA manager
    const manager = await prisma.dMAManager.create({
      data: {
        name: data.name,
        email: data.email,
        password: hashedPassword,
        phone: data.phone || null,
        status: data.status || 'active',
        utilityId: data.utilityId,
        dmaId: data.dmaId || null,
      },
      include: {
        utility: { select: { id: true, name: true } },
        dma: { select: { id: true, name: true } },
      },
    })

    return NextResponse.json({
      id: manager.id,
      name: manager.name,
      email: manager.email,
      phone: manager.phone,
      status: manager.status,
      role: 'dma_manager',
      utilityId: manager.utilityId,
      utilityName: manager.utility.name,
      dmaId: manager.dmaId,
      dmaName: manager.dma?.name || null,
      createdAt: manager.createdAt,
    }, { status: 201 })
  } catch (error) {
    console.error('Error creating DMA manager:', error)
    return NextResponse.json({ error: 'Failed to create DMA manager' }, { status: 500 })
  }
}

// PUT /api/dma-managers - Update a DMA manager
export async function PUT(request: NextRequest) {
  try {
    const data = await request.json()

    if (!data.id) {
      return NextResponse.json({ error: 'DMA Manager ID is required' }, { status: 400 })
    }

    // Check email uniqueness across all user tables (excluding current manager)
    if (data.email) {
      const emailCheck = await checkEmailUniqueness(data.email, data.id)
      if (!emailCheck.isUnique) {
        return NextResponse.json(
          { error: `This email is already in use by a ${emailCheck.foundIn}` },
          { status: 400 }
        )
      }
    }

    // Get current manager
    const currentManager = await prisma.dMAManager.findUnique({
      where: { id: data.id },
    })

    if (!currentManager) {
      return NextResponse.json({ error: 'DMA Manager not found' }, { status: 404 })
    }

    // Hash password if provided
    const hashedPassword = data.password ? await hashPassword(data.password) : null

    // If assigning to a new DMA, unassign any existing manager from this DMA first
    if (data.dmaId && data.dmaId !== currentManager.dmaId) {
      await prisma.$executeRaw`
        UPDATE "DMAManager" 
        SET "dmaId" = NULL, "updatedAt" = NOW()
        WHERE "dmaId" = ${data.dmaId} AND id != ${data.id}
      `
    }

    // Update password if provided
    if (hashedPassword) {
      await prisma.$executeRaw`
        UPDATE "DMAManager" 
        SET 
          name = ${data.name},
          email = ${data.email},
          phone = ${data.phone || null},
          status = ${data.status}::"EntityStatus",
          "dmaId" = ${data.dmaId || null},
          password = ${hashedPassword},
          "updatedAt" = NOW()
        WHERE id = ${data.id}
      `
    } else {
      await prisma.$executeRaw`
        UPDATE "DMAManager" 
        SET 
          name = ${data.name},
          email = ${data.email},
          phone = ${data.phone || null},
          status = ${data.status}::"EntityStatus",
          "dmaId" = ${data.dmaId || null},
          "updatedAt" = NOW()
        WHERE id = ${data.id}
      `
    }

    // Fetch the updated manager with relations
    const updatedManager = await prisma.dMAManager.findUnique({
      where: { id: data.id },
      include: {
        utility: { select: { id: true, name: true } },
        dma: { select: { id: true, name: true } },
      },
    })

    return NextResponse.json({
      id: updatedManager?.id,
      name: updatedManager?.name,
      email: updatedManager?.email,
      phone: updatedManager?.phone,
      status: updatedManager?.status,
      role: 'dma_manager',
      utilityId: updatedManager?.utilityId,
      utilityName: updatedManager?.utility?.name,
      dmaId: updatedManager?.dmaId,
      dmaName: updatedManager?.dma?.name || null,
      createdAt: updatedManager?.createdAt,
    })
  } catch (error) {
    console.error('Error updating DMA manager:', error)
    const errorMessage = error instanceof Error ? error.message : 'Failed to update DMA manager'
    return NextResponse.json({ error: errorMessage }, { status: 500 })
  }
}

// DELETE /api/dma-managers - Delete a DMA manager
export async function DELETE(request: NextRequest) {
  try {
    const { searchParams } = new URL(request.url)
    const id = searchParams.get('id')

    if (!id) {
      return NextResponse.json({ error: 'DMA Manager ID is required' }, { status: 400 })
    }

    // Delete the manager (dmaId will be set to null automatically)
    await prisma.dMAManager.delete({
      where: { id },
    })

    return NextResponse.json({ success: true })
  } catch (error) {
    console.error('Error deleting DMA manager:', error)
    return NextResponse.json({ error: 'Failed to delete DMA manager' }, { status: 500 })
  }
}